{
  "name": "Medicare Savings Programs (QMB, SLMB, QI)",
  "eligibility": {
    "age": null,
    "income_limits": "Federal limits for 2026 are higher in Hawaii. QMB: Individual $1,550/month, couple $2,095/month. SLMB: Individual $1,860/month (120% FPL), couple $2,514/month. QI: Individual $2,095/month (135% FPL), couple $2,830/month. Includes $20 general income disregard. Limits apply to countable monthly income; Hawaii may disregard additional amounts. Vary by program tier, not household size beyond couple. Older sources cite lower/varying figures like $1,094 individual for QMB or $6,600 annual, but use current federal-adjusted for Hawaii[1][5][6][7].",
    "asset_limits": "Individual: $9,950. Couple: $14,910. Counts: Bank accounts, stocks, bonds. Exempt: Home, one car, burial plots, life insurance (up to $1,500 face value), personal belongings. Hawaii follows federal resource limits; some states eliminate test but not confirmed here[2][3][5][6][7].",
    "other_requirements": ["Must be enrolled in Medicare Part A (free for most) and Part B for SLMB/QI.", "U.S. citizen or qualified immigrant.", "Hawaii resident.", "Not eligible for full Medicaid (QI specifically).", "QI first-come, first-served and annual reapplication."]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Pays Medicare Part A premium (if applicable, $0 for most), Part B premium ($202.90/month in 2026), Part A deductible ($1,604 est.), Part B deductible ($240 est.), coinsurance/copayments. SLMB/QI: Pays Part B premium only ($202.90/month). Automatic Extra Help for Part D drugs if eligible[1][3][6][7].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: medquest.hawaii.gov (MedQUEST portal)[10]", "Phone: Hawaii MedQUEST at (808) 587-7500 or toll-free 1-800-316-8005", "Mail/In-person: Local MedQUEST district offices (e.g., Oahu: 601 Kamokila Blvd, Kapolei)", "Through SHIP counselor: hawaiiship.org or 1-888-536-9117"],
    "processing_time": "Typically 45 days, but varies; no specific Hawaii timeline in results",
    "waitlist": "QI has first-come, first-served funding limits; may have waitlist if funds exhausted[1][3][6]",
    "forms": ["MedQUEST application (online form 03701 or equivalent via portal); no specific MSP-only form named"],
    "documents": ["Proof of income (SSI award, pay stubs, tax returns)", "Proof of resources (bank statements)", "Medicare card", "ID (birth certificate, driver's license)", "Proof of residency", "Household size details"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered uniformly statewide by MedQUEST, but apply via district offices; no noted differences in benefits/limits/wait times by island/county[10]",
    "offices_or_providers": ["MedQUEST offices: Oahu (Kapolei), Maui, Big Island, Kauai; statewide helpline"]
  },
  "official_source": "https://medquest.hawaii.gov/content/medquest/en/members-applicants/get-started/programs.html",
  "gotchas": ["Income/resource limits higher in Hawaii than mainland but still strict; outdated sources list old figures (e.g., 2021 $1,094)—verify current[1][5].", "QI requires annual reapplication and may run out of funds[1][6].", "QMB protects from provider billing (no balance billing), but providers must bill Medicare first[7].", "Automatic Extra Help/LIS eligibility often missed[6].", "Working income may allow higher qualification[6].", "Assets include spouse's even if not applying[2]."],
  "data_shape_notes": "Tiered by income (QMB <100% FPL, SLMB 100-120%, QI 120-135%); Hawaii has elevated income limits vs. mainland; QI funding capped first-come; benefits are premium/deductible payments, not direct services; statewide but local offices"
}

